<?php use App\Helpers\Csrf; use App\Helpers\Sanitizer; use App\Helpers\Url; ?>
<main class="container">
<section class="module-hero"><div><span class="eyebrow">Catálogo</span><h1>Autos de origen</h1><p>Registra marca, modelo y año de los vehículos de donde salen las piezas.</p></div><div class="action-row"><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/dashboard')) ?>">Panel</a><a class="btn" href="<?= Sanitizer::html(Url::ruta('/autos/crear')) ?>">Nuevo auto</a></div></section>
<section class="card"><form class="filter-form" method="GET" action="<?= Sanitizer::html(Url::ruta('/autos')) ?>"><div class="form-group"><label>Buscar</label><input name="buscar" value="<?= Sanitizer::html($busqueda ?? '') ?>" placeholder="Marca, modelo o año"></div><div class="form-group"><label>Estado</label><select name="estado"><option value="">Todos</option><option value="1" <?= ($estado ?? '')==='1'?'selected':'' ?>>Activos</option><option value="0" <?= ($estado ?? '')==='0'?'selected':'' ?>>Inactivos</option></select></div><div class="form-actions compact"><button class="btn">Filtrar</button><a class="btn btn-secundario" href="<?= Sanitizer::html(Url::ruta('/autos')) ?>">Limpiar</a></div></form></section>
<section class="card table-wrapper"><table><thead><tr><th>Marca</th><th>Modelo</th><th>Año</th><th>Descripción</th><th>Estado</th><th>Acciones</th></tr></thead><tbody><?php if(empty($autos)): ?><tr><td colspan="6" class="empty-state">No hay autos registrados.</td></tr><?php endif; ?><?php foreach($autos as $auto): ?><tr><td><?= Sanitizer::html($auto['marca']) ?></td><td><?= Sanitizer::html($auto['modelo']) ?></td><td><?= Sanitizer::html($auto['anio']) ?></td><td><?= Sanitizer::html($auto['descripcion'] ?? '') ?></td><td><?= (int)$auto['activo']===1?'<span class="badge badge-success">Activo</span>':'<span class="badge badge-danger">Inactivo</span>' ?></td><td class="acciones-tabla"><a class="btn btn-mini btn-secundario" href="<?= Sanitizer::html(Url::ruta('/autos/editar/'.$auto['id_auto'])) ?>">Editar</a><form method="POST" action="<?= Sanitizer::html(Url::ruta('/autos/estado/'.$auto['id_auto'])) ?>" data-confirm="¿Cambiar estado del auto?"><?= Csrf::campo() ?><input type="hidden" name="activo" value="<?= (int)$auto['activo']===1?0:1 ?>"><button class="btn btn-mini <?= (int)$auto['activo']===1?'btn-danger':'' ?>" type="submit"><?= (int)$auto['activo']===1?'Desactivar':'Activar' ?></button></form></td></tr><?php endforeach; ?></tbody></table></section>
</main>
